import{_ as e,c as a,a1 as s,o as p}from"./chunks/framework.B0cMFUTE.js";const c=JSON.parse('{"title":"如何推荐一本书 晨星LL","description":"","frontmatter":{"title":"如何推荐一本书 晨星LL","tags":["成长录"],"categories":["成长录"],"abbrlink":24091716,"date":"2024-09-17T16:39:44.000Z","updated":"2024-09-17 17:53"},"headers":[],"relativePath":"blog-essays/如何推荐一本书 晨星LL.md","filePath":"blog-essays/如何推荐一本书 晨星LL.md","lastUpdated":1735324345000}'),o={name:"blog-essays/如何推荐一本书 晨星LL.md"};function l(r,t,i,n,_,L){return p(),a("div",null,t[0]||(t[0]=[s("<p>推荐一本书不应该直接就讲它的具体内容，而是分享它吸引你的特点，所以需要分享之人总结出这本书的<strong>独特之处</strong>。</p><p>以《学霸的黑科技系统》为例，简单来概括，这本书讲述男主角陆舟获得系统后，加速科研，提升自身能力，不断突破各类学术界难题，并最终成为人类心智的荣耀的故事。</p><p>这本书本身涉及的元素有科幻、系统、数理科普，书中内容（科幻/科普内容）涉及有数学各大猜想和各大数学家、锂硫电池、可控核聚变、AI（小艾😘）、VR虚拟现实技术、人工智能危机、冷冻睡眠等</p><p>其独特之处如下：</p><ol><li>在现实上做文章，不为了科幻而科幻。这是该书与其他科幻小说最突出的区别，该书并不像《三体》等小说直接在虚构的未来进行创作，而是根据现实做出符合学界业界发展的预测。作者查阅各种文献资料，根据学术界各领域的主流研究方向，在现实的基础上，让未来大概率会突破的成果提前到现在的时间线中，从而使得小说十分真实，科技的走向十分符合直觉，而不显突兀。当各领域的主流研究方向都落实之后，现实不就是所谓的未来嘛。</li><li>行文严谨，前后各情节之间有逻辑（作者晨星LL每本书都是这个风格）。当理论研究的突破后，才有工业界产品的突破，比如文中锂枝晶问题得到解决后，才有了此后电池续航的提升。</li><li>以科研工作者的视角，探索可控核聚变、地月掌控等大工程的研发进程，突出主角等所有科研工作者的艰辛付出。</li><li>爽！</li></ol><p>晨星LL三部曲：《我在末世有套房》《学霸的黑科技系统》《这游戏也太真实了》</p><p>作者晨星LL人称“预言帝”，在2015年的小说《我在末世有套房》中预言了俄乌战争，7年后俄乌战争爆发被请去喝茶。</p><p>他的另一本书《这游戏也太真实了》也是一部神作，可以看做是《学霸的黑科技系统》的续作，摆脱了都市这一概念的束缚，在废土上充分发挥作者渊博的知识与想象力。讲述了在另一平行宇宙的地球上，因核战而进入了废土纪元，主角楚光协同玩家（第四天灾）一步步联合废土幸存者及其他势力，建立新联盟，结束废土纪元的过程。作者以真实的笔触，描写了两国战争中经济战的威力、强烈压迫下共产主义思想的启蒙等。战争与发展是本书的主旋律，歌颂勇气、歌颂人类本身。</p>",8)]))}const m=e(o,[["render",l]]);export{c as __pageData,m as default};
